const item = $input.first().json;

const errors = [];

const validCuisines = ['de', 'it', 'jp', 'in', 'gourmet', 'fusion'];
const validDiets = ['vegetarian', 'vegan', 'keto', 'none'];
const validTimeCategories = ['quick', 'medium', 'elaborate'];

const ingredients = Array.isArray(item.ingredients) ? item.ingredients : [];

const normalizedIngredients = ingredients
  .map((ingredient) => {
    const name = String(ingredient?.name ?? '').trim();
    return {
      ...ingredient,
      name,
    };
  })
  .filter((ingredient) => {
    const name = ingredient.name.toLowerCase();
    return (
      name.length >= 2 &&
      /[a-zA-ZäöüÄÖÜß]/.test(name) &&
      !/^\d+$/.test(name) &&
      name !== 'test' &&
      name !== 'asdf' &&
      name !== 'qwe'
    );
  });

if (normalizedIngredients.length === 0) {
  errors.push('At least one valid ingredient is required');
}

if (typeof item.servings !== 'number' || item.servings < 1 || item.servings > 12) {
  errors.push('servings must be between 1 and 12');
}

if (typeof item.helpers !== 'number' || item.helpers < 1 || item.helpers > 4) {
  errors.push('helpers must be between 1 and 4');
}

if (!validCuisines.includes(item.cuisine)) {
  errors.push('cuisine is invalid');
}

if (!validTimeCategories.includes(item.timeCategory)) {
  errors.push('timeCategory is invalid');
}

const diet = item.diet || 'none';
if (!validDiets.includes(diet)) {
  errors.push('diet is invalid');
}

return [
  {
    json: {
      ...item,
      ingredients: normalizedIngredients,
      diet,
      valid: errors.length === 0,
      errors
    }
  }
];

const item = $input.first().json;

const headers = $('Webhook').first().json.headers || {};

const forwardedFor = headers['x-forwarded-for'];
const realIp = headers['x-real-ip'];

let ip = 'unknown';

if (typeof forwardedFor === 'string' && forwardedFor.trim()) {
  ip = forwardedFor.split(',')[0].trim();
} else if (typeof realIp === 'string' && realIp.trim()) {
  ip = realIp.trim();
} else if (typeof headers.host === 'string' && headers.host.includes('localhost')) {
  ip = '127.0.0.1';
}

const now = new Date();
const dateKey = now.toISOString().slice(0, 10);
const quotaKey = `${ip}_${dateKey}`;

return [
  {
    json: {
      ...item,
      quota: {
        ip,
        dateKey,
        quotaKey,
        limitPerDay: 3
      }
    }
  }
];

const item = $input.first().json;

return [
  {
    json: {
      ...item,
      generationPlan: {
        includeLibraryRecipe: false,
        generateCount: 3
      }
    }
  }
];

const item = $input.first().json;

const promptData = {
  ingredients: item.ingredients || [],
  servings: item.servings,
  helpers: item.helpers,
  timeCategory: item.timeCategory,
  cuisine: item.cuisine,
  diet: item.diet,
  generateCount: 3,
  libraryContext: null
};

return [
  {
    json: {
      ...item,
      promptData
    }
  }
];

const item = $input.first().json;
const data = item.promptData;

const ingredientsText = (data.ingredients || [])
  .map((ingredient) => {
    const amount = ingredient.amount ?? '';
    const unit = ingredient.unit ?? '';
    const name = ingredient.name ?? '';
    return `- ${amount} ${unit} ${name}`.trim();
  })
  .join('\n');

const libraryContextText = data.libraryContext
  ? `
Existing library recipe already found:
- id: ${data.libraryContext.id}
- title: ${data.libraryContext.title}
- ingredients: ${(data.libraryContext.ingredients || []).join(', ')}
- cuisine: ${data.libraryContext.cuisine}
- diet: ${data.libraryContext.diet}
- timeCategory: ${data.libraryContext.timeCategory}

Generate new alternatives that are meaningfully different from this existing recipe.
`
  : `No existing library recipe was found.`;

const prompt = `
You are a recipe generation system.

Generate exactly ${data.generateCount} new recipe alternatives.

User constraints:
- servings: ${data.servings}
- helpers: ${data.helpers}
- timeCategory: ${data.timeCategory}
- cuisine: ${data.cuisine}
- diet: ${data.diet}

User ingredients:
${ingredientsText}

${libraryContextText}

Rules:
- Return valid JSON only.
- Do not return markdown.
- Generate exactly ${data.generateCount} recipes.
- Each recipe should use at least 70% of the provided user ingredients when possible.
- Each recipe may add at most 3 extra basic ingredients.
- The recipes must be clearly distinct from each other.
- If a library recipe is provided, the new recipes must be different from it.
- Steps must be chronological and easy to follow.
- Include helper task assignment for up to ${data.helpers} people.
- Include nutrition estimates.
- Nutrition must contain perPortion and total.
- Each nutrition object must include:
  calories, protein_g, carbs_g, fat_g

Return this JSON shape:
{
  "recipes": [
    {
      "title": "string",
      "description": "string",
      "servings": number,
      "cookTimeMinutes": number,
      "timeCategory": "quick | medium | elaborate",
      "cuisine": "de | it | jp | in | gourmet | fusion",
      "diet": "vegetarian | vegan | keto | none",
      "difficulty": "easy | medium | hard",
      "tags": ["string"],
      "ingredients": [
        {
          "name": "string",
          "amount": number,
          "unit": "string",
          "source": "user | extra"
        }
      ],
      "extraIngredients": [
        {
          "name": "string",
          "amount": number,
          "unit": "string",
          "reason": "basic"
        }
      ],
      "steps": [
        {
          "index": number,
          "title": "string",
          "description": "string",
          "durationMinutes": number,
          "parallelizable": true,
          "assignedTo": ["cook_1"]
        }
      ],
      "helperAssignments": [
        {
          "person": "cook_1",
          "stepIndexes": [1, 2]
        }
      ],
      "nutrition": {
        "perPortion": {
          "calories": number,
          "protein_g": number,
          "carbs_g": number,
          "fat_g": number
        },
        "total": {
          "calories": number,
          "protein_g": number,
          "carbs_g": number,
          "fat_g": number
        }
      }
    }
  ]
}
`.trim();

return [
  {
    json: {
      ...item,
      aiPrompt: prompt
    }
  }
];

const item = $input.first().json;

const rawText =
  item.content?.parts?.[0]?.text ||
  item.text ||
  item.output ||
  '';

if (!rawText || typeof rawText !== 'string') {
  throw new Error('No AI text response found');
}

let parsed;

try {
  parsed = JSON.parse(rawText);
} catch (error) {
  throw new Error(`Failed to parse AI JSON response: ${error.message}`);
}

return [
  {
    json: {
      ...item,
      aiRawText: rawText,
      aiParsed: parsed
    }
  }
];

const item = $input.first().json;

const recipes = Array.isArray(item.aiParsed?.recipes) ? item.aiParsed.recipes : [];

const generatedRecipes = recipes.map((recipe, index) => {
  const normalizedIngredients = Array.isArray(recipe.ingredients)
    ? recipe.ingredients.map((ingredient) => ({
        name: String(ingredient.name || '').trim(),
        amount: ingredient.amount ?? null,
        unit: ingredient.unit ?? '',
        source: ingredient.source === 'extra' ? 'extra' : 'user'
      }))
    : [];

  const normalizedExtraIngredients = Array.isArray(recipe.extraIngredients)
    ? recipe.extraIngredients.map((ingredient) => ({
        name: String(ingredient.name || '').trim(),
        amount: ingredient.amount ?? null,
        unit: ingredient.unit ?? '',
        reason: ingredient.reason || 'basic'
      }))
    : [];

  const normalizedSteps = Array.isArray(recipe.steps)
    ? recipe.steps.map((step, stepIndex) => ({
        index: step.index ?? stepIndex + 1,
        title: String(step.title || '').trim(),
        description: String(step.description || '').trim(),
        durationMinutes: step.durationMinutes ?? null,
        parallelizable: Boolean(step.parallelizable),
        assignedTo: Array.isArray(step.assignedTo) ? step.assignedTo : []
      }))
    : [];

  const helperAssignments = Array.isArray(recipe.helperAssignments)
    ? recipe.helperAssignments.map((assignment) => ({
        person: assignment.person || 'cook_1',
        stepIndexes: Array.isArray(assignment.stepIndexes) ? assignment.stepIndexes : []
      }))
    : [];

  return {
    source: 'generated',
    tempId: `generated_${index + 1}`,
    title: String(recipe.title || '').trim(),
    description: String(recipe.description || '').trim(),
    servings: recipe.servings ?? item.servings,
    cookTimeMinutes: recipe.cookTimeMinutes ?? null,
    timeCategory: recipe.timeCategory || item.timeCategory,
    cuisine: recipe.cuisine || item.cuisine,
    diet: recipe.diet || item.diet,
    difficulty: recipe.difficulty || 'medium',
    tags: Array.isArray(recipe.tags) ? recipe.tags : [],
    ingredients: normalizedIngredients,
    extraIngredients: normalizedExtraIngredients,
    steps: normalizedSteps,
    helperAssignments,
    nutrition: recipe.nutrition || {
      perPortion: {
        calories: null,
        protein_g: null,
        carbs_g: null,
        fat_g: null
      },
      total: {
        calories: null,
        protein_g: null,
        carbs_g: null,
        fat_g: null
      }
    }
  };
});

return [
  {
    json: {
      ...item,
      generatedRecipes
    }
  }
];

const item = $input.first().json;

return [
  {
    json: {
      ...item,
      recipes: Array.isArray(item.generatedRecipes) ? item.generatedRecipes : []
    }
  }
];

const recipesItem = $('Build Final Recipes List').first().json;
const quotaItem = $('Normalize Quota Counter').first().json;

return [
  {
    json: {
      success: true,
      libraryMatch: {
        hasMatch: recipesItem.libraryMatch?.hasMatch ?? false,
        bestMatchId: recipesItem.libraryMatch?.bestMatch?.id ?? null
      },
      quota: quotaItem.quota || null,
      recipes: recipesItem.recipes || []
    }
  }
];

const item = $input.first().json;

const recipes = Array.isArray(item.aiParsed?.recipes) ? item.aiParsed.recipes : [];
const expectedCount = item.generationPlan?.generateCount ?? 3;

const valid = recipes.length === expectedCount;

return [
  {
    json: {
      ...item,
      generationCountCheck: {
        expected: expectedCount,
        actual: recipes.length,
        valid
      }
    }
  }
];

