const sourceItem = $('Prepare Quota Data').first().json;
const firestoreDoc = $('Read Quota Counter').first()?.json ?? null;

const parsedCount = Number(firestoreDoc?.count ?? 0);
const usedToday = Number.isFinite(parsedCount) ? parsedCount : 0;

const existingQuota = sourceItem.quota || {};
const limitPerDay = existingQuota.limitPerDay ?? 3;
const remainingToday = Math.max(0, limitPerDay - usedToday);
const allowed = usedToday < limitPerDay;

return [
  {
    json: {
      ...sourceItem,
      quota: {
        ...existingQuota,
        usedToday,
        remainingToday,
        allowed
      }
    }
  }
];

const quota = $('Normalize Quota Counter').first().json.quota;

return [
  {
    json: {
      quotaKey: quota.quotaKey,
      ip: quota.ip,
      dateKey: quota.dateKey,
      count: (quota.usedToday || 0) + 1,
      updatedAt: new Date().toISOString()
    }
  }
];
